declare module "@wave-frontend/wave-js" {
  export class WaveApp {
    private selector: string;
    private stores: Array<WaveStore>;
    private dom: WaveDom | undefined;
    constructor(selector: string);
    public useStore(store: WaveStore): void;
    public useStores(...stores: Array<WaveStore>): void;
    public mount(): void;
    public unmount(): void;
    public getMount(): Element;
    private initializeMountedElement(): void;
    private initializeStatements(): Promise<void>;
    private onDataChange(instance: WaveStore, changedKey: string): void;
    private updateConditionals(): void;
    private getMergedStoreData(): WaveDictionary<any>;
    private getMergedStoreComponents(): WaveDictionary<WaveComponentHandler>;
  }

  export class WaveStore {
    public dataChangeCallbacks: Array<WaveDataChangeCallback>;
    private data: WaveDictionary<any>;
    private proxies: WaveDictionary<WaveProxyHandler>;
    private components: WaveDictionary<WaveComponentHandler>;
    constructor(from?: {
      data?: WaveDictionary<any>;
      proxies?: WaveDictionary<WaveProxyHandler>;
      components?: WaveDictionary<WaveComponentHandler>;
    });
    public setValue(key: string, value: any): Promise<void>;
    public getValue(key: string): any;
    public get(key: string): WaveStoreGetResult | undefined;
    public set(key: string, value: any): Promise<WaveStoreGetResult>;
    public setProxy(key: string, handler: WaveProxyHandler): void;
    public removeProxy(key: string): void;
    public getComponentHandler(key: string): WaveComponentHandler;
    public setComponentHandler(key: string, handler: WaveComponentHandler): void;
    public getDataKeys(): Array<string>;
    public getComponentKeys(): Array<string>;
    public addDataChangeCallback(callback: WaveDataChangeCallback): void;
  }

  export class WaveDom {
    private parent: Element;
    constructor(selector: string);
    public get root(): Element;
    public getAllElements(): Array<Element>;
    public getElementsByAttribute(attribute: string, value?: string): Array<Element>;
    public replace(match: string, replacement: string): void;
  }

  export interface WaveDictionary<T> {
    [key: string]: T;
  }

  export type WaveComponentHandler = (...args: Array<any>) => Promise<Element> | Element;

  export type WaveDataChangeCallback = (instance: WaveStore, changedKey: string) => void;

  export type WaveProxyHandler = (newValue: any) => Promise<boolean> | boolean;

  export interface WaveStoreGetResult {
    initialValue: any;
    getValue(): any;
    update(value: any): Promise<WaveStoreGetResult>;
  }
}